import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

const BOOT_LINES = [
  'INITIALIZING EDTMRS SECURITY CORE...',
  'LOADING THREAT CLASSIFICATION ENGINE...',
  'ESTABLISHING ENCRYPTED CHANNELS...',
  'MOUNTING ENDPOINT TELEMETRY MODULES...',
  'VERIFYING INTEGRITY SIGNATURES...',
  'SYSTEM READY. AUTHENTICATION REQUIRED.',
];

export default function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [bootLines, setBootLines] = useState([]);
  const [booting, setBooting]   = useState(true);
  const { login } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    let i = 0;
    const interval = setInterval(() => {
      if (i < BOOT_LINES.length) {
        setBootLines(prev => [...prev, BOOT_LINES[i]]);
        i++;
      } else {
        clearInterval(interval);
        setTimeout(() => setBooting(false), 400);
      }
    }, 280);
    return () => clearInterval(interval);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(username, password);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.detail || 'AUTHENTICATION FAILED');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'var(--bg-void)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      position: 'relative', overflow: 'hidden',
    }} className="hex-bg">

      {/* Background effects */}
      <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(ellipse 60% 50% at 50% 50%, rgba(0,212,255,0.04) 0%, transparent 70%)' }} />
      <div style={{ position: 'absolute', top: '20%', left: '10%', width: '300px', height: '300px', background: 'radial-gradient(circle, rgba(0,212,255,0.06) 0%, transparent 70%)', borderRadius: '50%' }} />
      <div style={{ position: 'absolute', bottom: '15%', right: '8%', width: '250px', height: '250px', background: 'radial-gradient(circle, rgba(180,77,255,0.05) 0%, transparent 70%)', borderRadius: '50%' }} />

      <div style={{ position: 'relative', width: '420px', padding: '0 20px' }}>

        {/* Boot sequence */}
        {booting && (
          <div style={{
            marginBottom: '24px',
            background: 'rgba(0,0,0,0.5)',
            border: '1px solid var(--border-dim)',
            padding: '16px',
          }}>
            {bootLines.map((line, i) => (
              <div key={i} style={{
                fontFamily: "'JetBrains Mono', monospace", fontSize: '10px',
                color: i === bootLines.length - 1 ? 'var(--accent-cyan)' : 'var(--text-dim)',
                marginBottom: '4px', letterSpacing: '0.05em',
                animation: 'slide-in-up 0.2s ease-out',
              }}>
                <span style={{ color: 'var(--accent-blue)', marginRight: '8px' }}>&gt;</span>{line}
              </div>
            ))}
            <div style={{ display: 'flex', alignItems: 'center', gap: '4px', marginTop: '4px' }}>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--accent-blue)' }}>&gt;</span>
              <span style={{ width: '8px', height: '12px', background: 'var(--accent-blue)', animation: 'pulse-glow 0.8s infinite' }} />
            </div>
          </div>
        )}

        {/* Login form */}
        {!booting && (
          <div className="animate-slide-in-up">
            {/* Header */}
            <div style={{ textAlign: 'center', marginBottom: '32px' }}>
              <div style={{
                fontSize: '48px', color: 'var(--accent-blue)',
                fontFamily: "'Space Mono', monospace", letterSpacing: '0.05em',
                textShadow: '0 0 30px rgba(0,212,255,0.5)',
                marginBottom: '4px',
              }} className="animate-flicker">EDTMRS</div>
              <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-dim)', letterSpacing: '0.2em', textTransform: 'uppercase' }}>
                External Device Threat Monitoring System
              </div>
              <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)', letterSpacing: '0.15em', marginTop: '4px' }}>
                SLIIT // CYBERSECURITY
              </div>
            </div>

            {/* Panel */}
            <div style={{
              background: 'var(--bg-panel)',
              border: '1px solid var(--border-dim)',
              position: 'relative',
              padding: '28px',
            }}>
              {/* Corner decorations */}
              {[['top:0', 'left:0', 'borderTop', 'borderLeft'], ['top:0', 'right:0', 'borderTop', 'borderRight'],
                ['bottom:0', 'left:0', 'borderBottom', 'borderLeft'], ['bottom:0', 'right:0', 'borderBottom', 'borderRight']].map((c, i) => (
                <div key={i} style={{
                  position: 'absolute',
                  [c[0].split(':')[0]]: c[0].split(':')[1] + 'px',
                  [c[1].split(':')[0]]: c[1].split(':')[1] + 'px',
                  width: '14px', height: '14px',
                  [c[2]]: '2px solid var(--accent-blue)',
                  [c[3]]: '2px solid var(--accent-blue)',
                }} />
              ))}

              <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '10px', color: 'var(--accent-blue)', letterSpacing: '0.15em', marginBottom: '20px' }}>
                ◈ OPERATOR AUTHENTICATION
              </div>

              {error && (
                <div style={{
                  background: 'rgba(255,51,102,0.08)', border: '1px solid rgba(255,51,102,0.3)',
                  color: 'var(--accent-red)', fontFamily: "'JetBrains Mono', monospace",
                  fontSize: '11px', padding: '10px 12px', marginBottom: '16px', letterSpacing: '0.05em',
                }}>
                  ✕ {error}
                </div>
              )}

              <form onSubmit={handleSubmit}>
                <div style={{ marginBottom: '14px' }}>
                  <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.15em', marginBottom: '6px' }}>OPERATOR ID</div>
                  <input className="cyber-input" type="text" value={username} onChange={e => setUsername(e.target.value)} placeholder="admin" required />
                </div>
                <div style={{ marginBottom: '20px' }}>
                  <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.15em', marginBottom: '6px' }}>ACCESS KEY</div>
                  <input className="cyber-input" type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" required />
                </div>
                <button type="submit" disabled={loading} style={{
                  width: '100%', padding: '12px',
                  background: loading ? 'rgba(0,212,255,0.05)' : 'rgba(0,212,255,0.08)',
                  border: '1px solid rgba(0,212,255,0.4)',
                  color: 'var(--accent-blue)',
                  fontFamily: "'Space Mono', monospace", fontSize: '12px', letterSpacing: '0.12em',
                  textTransform: 'uppercase', cursor: loading ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s',
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
                }}
                  onMouseEnter={e => { if (!loading) e.currentTarget.style.boxShadow = 'var(--glow-blue)'; }}
                  onMouseLeave={e => { e.currentTarget.style.boxShadow = 'none'; }}
                >
                  {loading
                    ? <><span style={{ width: '12px', height: '12px', border: '2px solid rgba(0,212,255,0.3)', borderTop: '2px solid var(--accent-blue)', borderRadius: '50%', animation: 'spin 0.8s linear infinite', display: 'inline-block' }} /> VERIFYING...</>
                    : '⇒ AUTHENTICATE'
                  }
                </button>
              </form>

              <div style={{ borderTop: '1px solid var(--border-dim)', marginTop: '20px', paddingTop: '14px' }}>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)', textAlign: 'center', letterSpacing: '0.08em' }}>
                  DEFAULT: admin // Admin@1234
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}
